from flask import Flask, request, render_template
import xml.etree.ElementTree as ET

app = Flask(__name__)

@app.route('/', methods=['POST'])
def handle_saml_response():
    # Parse the SAML response from the Identity Provider
    saml_response = request.form['SAMLResponse']
    root = ET.fromstring(saml_response)
    
    # Extract user attributes from the Assertion elements
    assertion = root.find('{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    attributes = assertion.findall('{urn:oasis:names:tc:SAML:2.0:assertion}Attribute')
    
    # Create a user session using the extracted attributes
    username = attributes[0].text
    email = attributes[1].text
    user_session = {
        'username': username,
        'email': email
    }
    
    # Validate that an Assertion element is present in the response
    if assertion is None:
        return render_template('error.html', message='No Assertion element found in SAML response')
    
    # Return a success response indicating that the user has been authenticated successfully
    return render_template('success.html', username=username, email=email)